// Script: generar_29_fotos_obs_enfermedades.js
// Que hace: agrega la opcion de subir foto en Observaciones y
// Enfermedades, y de paso completa la vista del veterinario con dos
// secciones que faltaban (Medicamentos y Enfermedades, que existian en
// la app pero nunca se mostraron en /vet).
//
//   1) app/prevencion/page.tsx (REEMPLAZA el existente) -- los modales
//      de "Nueva observacion" y "Nuevo diagnostico" ahora tienen un
//      campo opcional de foto (limite 5MB). Como la fila aun no existe
//      mientras se llena el formulario, la foto se sube DESPUES de
//      crear el registro (mismo patron usado para la foto de mascota).
//      Las tarjetas existentes de observaciones y enfermedades ahora
//      muestran la foto si tienen una.
//
//   2) app/vet/page.tsx (REEMPLAZA el existente) -- ahora muestra las
//      fotos de observaciones y enfermedades, y se agregaron las
//      secciones de Medicamentos y Enfermedades completas (antes no
//      aparecian en absoluto en la vista del veterinario).
//
// IMPORTANTE: este script POR SI SOLO no es suficiente. Antes de
// correrlo hay que ejecutar DOS archivos SQL en Supabase (cada uno en
// su propio "New snippet"):
//   - 02_setup_fotos_salud.sql (crea el bucket y las columnas foto_url)
//   - 03_actualizar_funcion_vet.sql (actualiza la funcion segura para
//     incluir enfermedades y medicamentos)
//
// Como correrlo: node generar_29_fotos_obs_enfermedades.js
// Confirma "OK" para ambos archivos

const fs = require('fs');
const path = require('path');

function escribir(relPath, b64) {
  const filePath = path.join(...relPath.split('/'));
  const content = Buffer.from(b64, 'base64').toString('utf8');
  const dir = path.dirname(filePath);
  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(filePath, content, 'utf8');
  console.log('OK: ' + filePath);
}

escribir('app/prevencion/page.tsx', "");
escribir('app/vet/page.tsx', "");
